        self.loss_func = loss_func

    def fit(self): ...

    def predict(self): ...


class RegressFactory:
    LOSS_FUNCS = {
        "MAE": MAEFunc,
        "RMSE": RMSEFunc
    }

    MODELS = {
        "A": RegressModelA,
        "B": RegressModelB
    }

    def __init__(self, model_name):
        self.model_name = model_name

    def create_model(self, loss_func_name):
        loss_cls = RegressFactory.LOSS_FUNCS.get(loss_func_name)
        model_cls = RegressFactory.MODELS.get(self.model_name)

        if loss_cls is None or model_cls is None:
            raise ValueError(f"Unknown loss_func '{loss_func_name}' or model '{self.model_name}'")

        return model_cls(loss_cls())


