def vikings_count(arr):
    count=0
    for _ in arr:
        count+=1
    return count

assert vikings_count([1, 2, 3]) == 3

def vikings_sum(arr):
    sum_of_clan=0
    for el in arr:
        sum_of_clan+=el
    return sum_of_clan

assert vikings_sum([1, 2, 3]) == 6

def vikings_mean(arr)->float:
    return vikings_sum(arr) / vikings_count(arr)

assert vikings_mean([1, 2, 3]) == 2.0

def vikings_median(arr):

    arr = sorted(arr)
    l = vikings_count(arr)
    if l%2:
        return arr[l//2]
    else:
        return vikings_mean(arr[l//2-1:l//2+1])


assert vikings_median([8,1,2,6,4])==4
assert vikings_median([1,2,3,3,3,4,5,100])==3
